AdvertConfig = {}
AdvertConfig.CardAds = {}
AdvertConfig.PropAds = {}

function AdvertConfig:initConfig(adverts)
    for _, item in pairs(adverts) do
        local advert = {}
        advert.id = tonumber(item.id)
        advert.poolId = tonumber(item.poolId)
        advert.seconds = tonumber(item.seconds)

        if tonumber(item.type) == Define.AdType.AD_CARD then
            table.insert(self.CardAds, advert)
        elseif (tonumber(item.type) == Define.AdType.AD_PROP) then
            table.insert(self.PropAds, advert)
        end
    end

    table.sort(self.CardAds, function(a, b)
        return a.id < b.id
    end)
    table.sort(self.PropAds, function(a, b)
        return a.id < b.id
    end)
end

function AdvertConfig:initPlayerAds(player)
    if player.advert_record == nil then
        player.advert_record = {
            DayKey = "",
            CardAdTimes = 0,
            PropAdTimes = 0,
        }
    end
    local key = DateUtil.getYearDay()
    if player.advert_record.DayKey ~= key then
        player.advert_record = {
            DayKey = key,
            CardAdTimes = 0,
            PropAdTimes = 0,
        }
    end
    self:syncCardAdInfo(player)
    self:syncPropAdInfo(player)
end

function AdvertConfig:getCardAdByTimes(times)
    if times <= 0 then
        return nil
    end
    if times > #self.CardAds then
        return nil
    end
    return self.CardAds[times]
end

function AdvertConfig:getPropAdByTimes(times)
    if times <= 0 then
        return nil
    end
    if times > #self.PropAds then
        return nil
    end
    return self.PropAds[times]
end

function AdvertConfig:doCardAdReward(player)
    local times = player.advert_record.CardAdTimes + 1
    local advert = AdvertConfig:getCardAdByTimes(times)
    if not advert then
        return
    end
    player.advert_record.CardAdTimes = times
    self:syncCardAdInfo(player)

    local reward = RewardConfig:getRewardByPool(advert.poolId)
    if not reward then
        return
    end
    RewardUtil:doReward(player, reward)
    GamePacketSender:sendAdvertRewardData(player.rakssid, Define.AdType.AD_CARD, reward.Id)
end

function AdvertConfig:doPropAdReward(player)
    local times = player.advert_record.PropAdTimes + 1
    local advert = AdvertConfig:getPropAdByTimes(times)
    if not advert then
        return
    end
    player.advert_record.PropAdTimes = times
    self:syncPropAdInfo(player)

    local reward = RewardConfig:getRewardByPool(advert.poolId)
    if not reward then
        return
    end
    RewardUtil:doReward(player, reward)
    GamePacketSender:sendAdvertRewardData(player.rakssid, Define.AdType.AD_PROP, reward.Id)
end

function AdvertConfig:syncCardAdInfo(player)
    player.advert_record.CardAdTimes = player.advert_record.CardAdTimes or 0
    local times = #self.CardAds - player.advert_record.CardAdTimes
    local advert = self:getCardAdByTimes(player.advert_record.CardAdTimes + 1)
    local seconds = 0
    if advert then
        seconds = advert.seconds
    end
    GamePacketSender:sendAdvertData(player.rakssid, Define.AdType.AD_CARD, times, seconds)
end

function AdvertConfig:syncPropAdInfo(player)
    player.advert_record.PropAdTimes = player.advert_record.PropAdTimes or 0
    local times = #self.PropAds - player.advert_record.PropAdTimes
    local advert = self:getPropAdByTimes(player.advert_record.PropAdTimes + 1)
    local seconds = 0
    if advert then
        seconds = advert.seconds
    end
    GamePacketSender:sendAdvertData(player.rakssid, Define.AdType.AD_PROP, times, seconds)
end